shaders.invert:
precision mediump float;
uniform sampler2D u_texture;
varying vec2 v_uv;
void main() {
  vec4 c = texture2D(u_texture, v_uv);
  gl_FragColor = vec4(1.0 - c.rgb, c.a);
}

shaders.crt:
precision mediump float;
uniform sampler2D u_texture;
uniform vec2 u_resolution;
varying vec2 v_uv;
void main() {
  vec4 c = texture2D(u_texture, v_uv);
  float row = floor(v_uv.y * u_resolution.y);
  float scan = mod(row, 2.0);
  c.rgb *= 1.0 - 0.15 * scan;
  // RGB triad shimmer
  float col = floor(v_uv.x * u_resolution.x);
  float band = mod(col, 3.0);
  vec3 mask = vec3(band == 0.0 ? 1.0 : 0.85, band == 1.0 ? 1.0 : 0.85, band == 2.0 ? 1.0 : 0.85);
  c.rgb *= mask;
  gl_FragColor = vec4(c.rgb, 1.0);
}

shaders.underwater:
precision mediump float;
uniform sampler2D u_texture;
uniform float u_time;
varying vec2 v_uv;
void main() {
  vec2 ripple = vec2(
    sin(v_uv.y * 30.0 + u_time * 1.5) * 0.005,
    cos(v_uv.x * 25.0 + u_time * 1.2) * 0.005
  );
  vec3 c = texture2D(u_texture, v_uv + ripple).rgb;
  // Underwater blue tint
  c = mix(c, c * vec3(0.6, 0.85, 1.05), 0.6);
  // Caustic bands
  float caustic = pow(
    sin(v_uv.x * 12.0 + u_time) * sin(v_uv.y * 10.0 - u_time * 0.7),
    2.0
  );
  c += caustic * vec3(0.1, 0.18, 0.22);
  gl_FragColor = vec4(clamp(c, 0.0, 1.0), 1.0);
}

shaders.vignette:
precision mediump float;
uniform sampler2D u_texture;
varying vec2 v_uv;
void main() {
  vec3 c = texture2D(u_texture, v_uv).rgb;
  float d = distance(v_uv, vec2(0.5));
  float v = smoothstep(0.7, 0.3, d);
  gl_FragColor = vec4(c * v, 1.0);
}

shaders.neon:
precision mediump float;
uniform sampler2D u_texture;
uniform vec2 u_resolution;
uniform float u_time;
varying vec2 v_uv;
void main() {
  vec3 base = texture2D(u_texture, v_uv).rgb;
  vec2 px = 1.0 / u_resolution;
  vec3 bloom = vec3(0.0);
  float wsum = 0.0;
  for (float dx = -3.0; dx <= 3.0; dx += 1.0) {
    for (float dy = -3.0; dy <= 3.0; dy += 1.0) {
      vec3 s = texture2D(u_texture, v_uv + vec2(dx, dy) * px * 2.0).rgb;
      float lum = dot(s, vec3(0.2126, 0.7152, 0.0722));
      float w = smoothstep(0.55, 0.95, lum);
      bloom += s * w;
      wsum += w;
    }
  }
  bloom /= max(wsum, 1.0);
  float pulse = 0.7 + 0.3 * sin(u_time * 2.5);
  vec3 tint = mix(bloom, bloom.brg, 0.5) * pulse;
  gl_FragColor = vec4(clamp(base + tint * 1.2, 0.0, 1.0), 1.0);
}

shaders.sepia:
precision mediump float;
uniform sampler2D u_texture;
varying vec2 v_uv;
void main() {
  vec3 c = texture2D(u_texture, v_uv).rgb;
  // Standard sepia matrix
  vec3 sepia = vec3(
    dot(c, vec3(0.393, 0.769, 0.189)),
    dot(c, vec3(0.349, 0.686, 0.168)),
    dot(c, vec3(0.272, 0.534, 0.131))
  );
  gl_FragColor = vec4(clamp(sepia, 0.0, 1.0), 1.0);
}

shaders.posterize:
precision mediump float;
uniform sampler2D u_texture;
varying vec2 v_uv;
void main() {
  vec3 c = texture2D(u_texture, v_uv).rgb;
  float bands = 4.0;
  c = floor(c * bands) / (bands - 1.0);
  gl_FragColor = vec4(clamp(c, 0.0, 1.0), 1.0);
}

shaders.pixelate:
precision mediump float;
uniform sampler2D u_texture;
uniform vec2 u_resolution;
varying vec2 v_uv;
void main() {
  // 16x16 pixel blocks regardless of resolution
  vec2 cell = vec2(16.0) / u_resolution;
  vec2 snapped = (floor(v_uv / cell) + 0.5) * cell;
  gl_FragColor = vec4(texture2D(u_texture, snapped).rgb, 1.0);
}

shaders.thermal:
precision mediump float;
uniform sampler2D u_texture;
varying vec2 v_uv;
void main() {
  vec3 c = texture2D(u_texture, v_uv).rgb;
  float t = dot(c, vec3(0.2126, 0.7152, 0.0722));
  // Cool→hot ramp: black → blue → purple → red → yellow → white
  vec3 col;
  if (t < 0.25)      col = mix(vec3(0.0, 0.0, 0.0), vec3(0.0, 0.0, 0.6), t / 0.25);
  else if (t < 0.5)  col = mix(vec3(0.0, 0.0, 0.6), vec3(0.5, 0.0, 0.6), (t - 0.25) / 0.25);
  else if (t < 0.7)  col = mix(vec3(0.5, 0.0, 0.6), vec3(0.95, 0.1, 0.05), (t - 0.5) / 0.2);
  else if (t < 0.9)  col = mix(vec3(0.95, 0.1, 0.05), vec3(1.0, 0.95, 0.1), (t - 0.7) / 0.2);
  else               col = mix(vec3(1.0, 0.95, 0.1), vec3(1.0, 1.0, 1.0), (t - 0.9) / 0.1);
  gl_FragColor = vec4(clamp(col, 0.0, 1.0), 1.0);
}

shaders.glitch:
precision mediump float;
uniform sampler2D u_texture;
uniform float u_time;
varying vec2 v_uv;
void main() {
  float offset = 0.008 + 0.004 * sin(u_time * 3.0);
  float r = texture2D(u_texture, v_uv + vec2( offset, 0.0)).r;
  float g = texture2D(u_texture, v_uv).g;
  float b = texture2D(u_texture, v_uv + vec2(-offset, 0.0)).b;
  gl_FragColor = vec4(r, g, b, 1.0);
}
